}

void backtrack(int[] nums, List<Integer> cur, boolean[] used) {
  if (cur.size() == nums.length) { res.add(new ArrayList<>(cur)); return; }
  for (int i = 0; i < nums.length; i++) {
    if (used[i]) continue;
    used[i] = true;
    cur.add(nums[i]);
    backtrack(nums, cur, used);
    cur.remove(cur.size() - 1);
    used[i] = false;
  }
}

